// All items mode
const staticData = $getWorkflowStaticData('global');
const processedIds = staticData.processedMessageIds || [];
const messageId = $json.messageId || $json.id || '';

if (!messageId || processedIds.includes(messageId)) {
  return []; // Already processed or no ID
}

return [{
  json: {
    ...$json,
    _messageId: messageId,
  }
}];

// All items mode
const item = $json;
const attachments = item.attachments || [];

// Find first valid attachment (pdf, jpg, jpeg, png, webp)
const validTypes = ['application/pdf', 'image/jpeg', 'image/jpg', 'image/png', 'image/webp'];
const attachment = attachments.find(a => validTypes.includes(a.mimeType?.toLowerCase()) || 
  ['pdf','jpg','jpeg','png','webp'].some(ext => (a.name||'').toLowerCase().endsWith('.'+ext)));

if (!attachment) return [];

// Get binary data - in n8n, attachment comes as base64 in attachment.content
const base64Data = attachment.content || '';
const mimeType = attachment.mimeType || 'image/jpeg';
const attachmentType = mimeType.includes('pdf') ? 'pdf' : 'image';

return [{
  json: {
    email_from: item.from?.value?.[0]?.address || item.from || '',
    email_subject: item.subject || '',
    email_message_id: item._messageId || item.messageId || '',
    attachment_type: attachmentType,
    attachment_name: attachment.name || 'attachment',
    base64_data: base64Data,
    mime_type: mimeType,
    _messageId: item._messageId || '',
  }
}];

