// All items mode
const responseContent = $json.choices?.[0]?.message?.content || '{}';

let extracted = {};
try {
  extracted = JSON.parse(responseContent);
} catch(e) {
  // Try to extract JSON from markdown code block
  const match = responseContent.match(/```(?:json)?\n?([\s\S]*?)\n?```/);
  if (match) {
    try { extracted = JSON.parse(match[1]); } catch(e2) {}
  }
}

const invoiceId = 'INV-' + Date.now();
const input = $('PrepareForGroq').first().json;

return [{
  json: {
    invoice_id: invoiceId,
    vendor_name: extracted.vendor_name || '',
    vendor_cif: extracted.vendor_cif || '',
    invoice_number: extracted.invoice_number || '',
    invoice_date: extracted.invoice_date || null,
    due_date: extracted.due_date || null,
    subtotal: parseFloat(extracted.subtotal) || 0,
    tax_rate: parseFloat(extracted.tax_rate) || 21,
    tax_amount: parseFloat(extracted.tax_amount) || 0,
    total: parseFloat(extracted.total) || 0,
    currency: extracted.currency || 'EUR',
    payment_concept: extracted.payment_concept || '',
    bank_iban: extracted.bank_iban || '',
    line_items: JSON.stringify(extracted.line_items || []),
    confidence_score: parseFloat(extracted.confidence_score) || 0.5,
    email_from: input.email_from,
    email_subject: input.email_subject,
    email_message_id: input.email_message_id,
    attachment_type: input.attachment_type,
    raw_llm_output: responseContent,
    status: 'pending',
    _messageId: input._messageId,
  }
}];

