const messageId = $json._messageId || '';

if (messageId && !processedIds.includes(messageId)) {
  processedIds.push(messageId);
  // Keep only last 1000 IDs
  if (processedIds.length > 1000) processedIds.shift();
  staticData.processedMessageIds = processedIds;
}

return [{ json: { success: true, invoice_id: $json.invoice_id } }];

